import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { motion } from "framer-motion";
import { useCart } from "../context/CartContext";
import Footer from './Footer';

const SingleProduct = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedImage, setSelectedImage] = useState(0);
  const { addToCart } = useCart();
  const [toastMessage, setToastMessage] = useState("");

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const response = await axios.get(`http://localhost:3000/api/v1/products/${id}`);
        setProduct(response.data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
  }, [id]);

  const handleAddToCart = () => {
    addToCart(product);
    setToastMessage("Added to cart!");
    setTimeout(() => setToastMessage(""), 3000);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-black text-white py-20">
        <div className="container mx-auto px-4">
          <div className="animate-pulse">
            {/* Add loading skeleton here */}
          </div>
        </div>
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="min-h-screen bg-black text-white py-20">
        <div className="container mx-auto px-4 text-center">
          <h2 className="text-2xl text-red-500 mb-4">Error Loading Product</h2>
          <p className="text-gray-400">{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white pt-16">
      <div className="container mx-auto px-4 py-12">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
          {/* Image Section */}
          <div className="space-y-6">
            <div className="aspect-square bg-zinc-900 rounded-2xl overflow-hidden">
              <img 
                src={product.images?.[selectedImage] || product.image} 
                alt={product.name}
                className="w-full h-full object-cover"
              />
            </div>
            {product.images?.length > 0 && (
              <div className="grid grid-cols-4 gap-4">
                {product.images.map((image, index) => (
                  <button
                    key={index}
                    onClick={() => setSelectedImage(index)}
                    className={`aspect-square rounded-lg overflow-hidden border-2 
                      ${selectedImage === index ? 'border-red-500' : 'border-transparent'}`}
                  >
                    <img 
                      src={image} 
                      alt={`${product.name} view ${index + 1}`}
                      className="w-full h-full object-cover"
                    />
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Product Details */}
          <div className="space-y-6">
            <div>
              <h1 className="text-4xl font-bold mb-2">{product.name}</h1>
              <div className="flex items-center gap-4 text-gray-400">
                <span>{product.category?.name}</span>
                <span>•</span>
                <span>Stock: {product.stock}</span>
                {product.stock <= 5 && (
                  <span className="text-yellow-500">• Low Stock</span>
                )}
              </div>
            </div>

            <div className="flex items-baseline gap-4">
              <span className="text-4xl font-bold">${product.price}</span>
              {product.oldPrice && (
                <span className="text-xl text-gray-400 line-through">
                  ${product.oldPrice}
                </span>
              )}
            </div>

            <p className="text-gray-300 text-lg leading-relaxed">
              {product.description}
            </p>

            <div className="flex flex-wrap gap-2">
              {product.tags?.map(tag => (
                <span 
                  key={tag}
                  className="px-3 py-1 bg-zinc-800 rounded-full text-sm text-gray-300"
                >
                  {tag}
                </span>
              ))}
            </div>

            <div className="flex gap-4">
              <button
                onClick={handleAddToCart}
                className="flex-1 px-8 py-4 bg-red-500 rounded-full text-white text-lg font-bold
                  transition-all duration-300 hover:bg-red-600 hover:shadow-[0_0_15px_rgba(239,68,68,0.3)]"
              >
                Add to Cart
              </button>
              <button className="p-4 rounded-full border border-zinc-700 hover:border-red-500 
                transition-colors text-red-500">
                <i className="far fa-heart text-xl"></i>
              </button>
            </div>

            {/* Additional Product Details */}
            <div className="border-t border-zinc-800 pt-6 mt-8">
              <h3 className="text-xl font-bold mb-4">Product Details</h3>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <p className="text-gray-400">Release Date</p>
                  <p>{new Date(product.dateCreated).toLocaleDateString()}</p>
                </div>
                <div className="space-y-2">
                  <p className="text-gray-400">Scale</p>
                  <p>1:64</p>
                </div>
                <div className="space-y-2">
                  <p className="text-gray-400">Material</p>
                  <p>Die-cast metal</p>
                </div>
                <div className="space-y-2">
                  <p className="text-gray-400">Series</p>
                  <p>{product.category?.name}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Toast Message */}
      {toastMessage && (
        <div className="fixed top-4 left-1/2 transform -translate-x-1/2 bg-green-500 text-white 
          px-6 py-3 rounded shadow-lg z-50">
          {toastMessage}
        </div>
      )}

      <Footer />
    </div>
  );
};

export default SingleProduct;
